def _print_Add(self, expr, order=None):
    if self.order == 'none':
        terms = list(expr.args)
    else:
        terms = self._as_ordered_terms(expr, order=order)

    PREC = precedence(expr)
    l = []
    for term in terms:
        t = self._print(term)
        if t.startswith('-'):
            sign = "-"
            t = t[1:]
        else:
            sign = "+"
        if precedence(term) < PREC:
            l.extend([sign, "(%s)" % t])
        else:
            l.extend([sign, t])
    sign = l.pop(0)
    if sign == '+':
        sign = ""
    return sign + ' '.join(l)

